webApi.a:expression:
a!localVariables(
  local!value: cast(
    #"urn:appian:record-type:v1:89604624-c221-4718-80d5-f26a57836ac8",
    #"SYSTEM_SYSRULES_fromJson_v1"(http!request.body)
  ),
  #"SYSTEM_SYSRULES_writeRecords_v2"(
    records: local!value,
    /*
    * Construct an HTTP response to return to the caller
    */
    onSuccess: #"SYSTEM_SYSRULES_httpResponse_v1"(
      statusCode: 200,
      /*
      * Set an HTTP header that tells the client that the body of the response will be in JSON format
      */
      headers: {
        #"SYSTEM_SYSRULES_httpHeader"(name: "Content-Type", value: "application/json")
      },
      /*
      *In the response body, return the records created or updated
      */
      body: #"SYSTEM_SYSRULES_toJson_v1"(fv!recordsUpdated)
    ),
    onError: #"SYSTEM_SYSRULES_httpResponse_v1"(
      statusCode: 500,
      headers: {
        #"SYSTEM_SYSRULES_httpHeader"(name: "Content-Type", value: "application/json")
      },
      body: #"SYSTEM_SYSRULES_toJson_v1"(
        a!map(
          message: "Write request has failed",
          error: fv!error
        )
      )
    )
  )
)
